-- Farmasi Quiz / EMS Weekly Quiz
-- Generated for Rekap Farmasi weekly quiz feature

CREATE TABLE IF NOT EXISTS farmasi_quiz_questions (
    id INT UNSIGNED NOT NULL AUTO_INCREMENT,
    question_code VARCHAR(32) NOT NULL,
    category VARCHAR(100) NOT NULL,
    prompt TEXT NOT NULL,
    option_a TEXT NOT NULL,
    option_b TEXT NOT NULL,
    option_c TEXT NOT NULL,
    option_d TEXT NOT NULL,
    option_e TEXT NOT NULL,
    correct_option CHAR(1) NOT NULL,
    explanation TEXT NOT NULL,
    is_active TINYINT(1) NOT NULL DEFAULT 1,
    created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
    PRIMARY KEY (id),
    UNIQUE KEY uniq_farmasi_quiz_question_code (question_code),
    KEY idx_farmasi_quiz_questions_active_category (is_active, category)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS farmasi_quiz_sessions (
    id BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,
    session_key VARCHAR(64) NOT NULL,
    user_id INT NOT NULL,
    display_name VARCHAR(190) NOT NULL,
    week_start DATE NOT NULL,
    generated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
    expires_at DATETIME NOT NULL,
    completed_at DATETIME NULL DEFAULT NULL,
    total_questions INT NOT NULL DEFAULT 10,
    score_correct INT NOT NULL DEFAULT 0,
    score_wrong INT NOT NULL DEFAULT 0,
    points INT NOT NULL DEFAULT 0,
    pass_status ENUM('pending','passed','failed') NOT NULL DEFAULT 'pending',
    created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
    PRIMARY KEY (id),
    UNIQUE KEY uniq_farmasi_quiz_session_key (session_key),
    KEY idx_farmasi_quiz_sessions_user_week (user_id, week_start),
    KEY idx_farmasi_quiz_sessions_active (week_start, completed_at, expires_at)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS farmasi_quiz_session_questions (
    id BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,
    session_id BIGINT UNSIGNED NOT NULL,
    question_id INT UNSIGNED NOT NULL,
    question_order INT NOT NULL,
    prompt TEXT NOT NULL,
    category VARCHAR(100) NOT NULL,
    option_a TEXT NOT NULL,
    option_b TEXT NOT NULL,
    option_c TEXT NOT NULL,
    option_d TEXT NOT NULL,
    option_e TEXT NOT NULL,
    correct_option CHAR(1) NOT NULL,
    explanation TEXT NOT NULL,
    selected_option CHAR(1) NULL DEFAULT NULL,
    is_correct TINYINT(1) NULL DEFAULT NULL,
    answered_at DATETIME NULL DEFAULT NULL,
    created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
    PRIMARY KEY (id),
    UNIQUE KEY uniq_farmasi_quiz_session_question (session_id, question_order),
    KEY idx_farmasi_quiz_session_questions_question (question_id),
    CONSTRAINT fk_farmasi_quiz_sq_session FOREIGN KEY (session_id) REFERENCES farmasi_quiz_sessions(id) ON DELETE CASCADE,
    CONSTRAINT fk_farmasi_quiz_sq_question FOREIGN KEY (question_id) REFERENCES farmasi_quiz_questions(id) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS farmasi_quiz_weekly_scores (
    id BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,
    week_start DATE NOT NULL,
    user_id INT NOT NULL,
    display_name VARCHAR(190) NOT NULL,
    points INT NOT NULL DEFAULT 0,
    correct_answers INT NOT NULL DEFAULT 0,
    wrong_answers INT NOT NULL DEFAULT 0,
    completed_sessions INT NOT NULL DEFAULT 0,
    passed_sessions INT NOT NULL DEFAULT 0,
    created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
    PRIMARY KEY (id),
    UNIQUE KEY uniq_farmasi_quiz_weekly_score (week_start, user_id),
    KEY idx_farmasi_quiz_weekly_ranking (week_start, points, correct_answers, wrong_answers)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS farmasi_quiz_weekly_history (
    id BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,
    season_label VARCHAR(120) NOT NULL,
    week_start DATE NOT NULL,
    week_end DATE NOT NULL,
    winner_user_id INT NOT NULL,
    winner_name VARCHAR(190) NOT NULL,
    points INT NOT NULL DEFAULT 0,
    correct_answers INT NOT NULL DEFAULT 0,
    wrong_answers INT NOT NULL DEFAULT 0,
    completed_sessions INT NOT NULL DEFAULT 0,
    passed_sessions INT NOT NULL DEFAULT 0,
    finalized_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
    created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
    PRIMARY KEY (id),
    UNIQUE KEY uniq_farmasi_quiz_week_history (week_start),
    KEY idx_farmasi_quiz_week_history_recent (week_start DESC)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

DELETE FROM farmasi_quiz_questions;

